const msg = $input.first().json.message;
if (!msg || !msg.reply_to_message) {
  // Ignore messages that are not replies to the bot
  return [];
}

const replyText = msg.reply_to_message.text || "";

// Extract the hidden tagging
const tagMatch = replyText.match(/\[MSG:(.*?)\|TO:(.*?)\]/);
if (!tagMatch) {
  return [];
}

const email_id = tagMatch[1];
const to_address = tagMatch[2];

const userText = (msg.text || "").trim();
let emailBody = userText;

// If the user simply types 'send', extract the AI draft to send instead
if (userText.toLowerCase() === 'send' || userText.toLowerCase() === 'approve') {
    // Draft is sandwiched between "Suggested Reply:" and the pleasant signature/tags
    const parts = replyText.split("Suggested Reply:");
    if (parts.length > 1) {
        let draft_section = parts[1].split("Wishing you")[0].split("Make it")[0].split("Keep up")[0].split("Have a")[0].split("Here's")[0].split("Stay")[0].split("[MSG:")[0];
        emailBody = draft_section.trim();
    }
}

return {
  json: {
    n8n_thread_id: email_id,
    client_email: to_address,
    final_body_to_send: emailBody
  }
};
